import logo from './logo.svg';
import './App.css';
import React, { useState } from 'react';

function App() {

  //왜 state 변경한 것들이 새로고침하면 없어짐? -> 새로고침 시 html, js 파일 다시 읽어서 그럼 (싫으면 서버로 보내서 DB에 영구저장하면 됨)
  let post_MainName = "음악 잘하는 기처리!";
  let logoText = "기처리 블로그임!";
  let [글제목, 글제목변경] = useState(['기처리의 러닝화 추천', '희선이의 음악 추천', '주노의 영화 추천']);
  // let [DDabong, plus_DDabong] = useState([0,0,0]);
  let [Views, plus_views] = useState([0,0,0]);
  let [입력값, 입력값변경] = useState('');

  let [modal, setModal] = useState(null);
  let now = new Date(); //날짜
  let [writtenTime, setWrittenTime] = useState([now.toLocaleTimeString(),now.toLocaleTimeString(), now.toLocaleTimeString()])

  

  //map 함수.. 특징? (비슷한 html 반복 생성하려면.. map() 쓰면 된다!)
  //1. 왼쪽 array 자료만큼 내부코드 실행해줌
  //2. return 오른쪽에 있는 걸 array로 담아줌
  //3. 유용한 파라미터 2개 사용 가능
  글제목.map(function(a, i){
    return (
      <div className="list">
        <h4>{글제목[i]}</h4>
        <p>2월 16일 발행</p>
      </div>
    )
  })

  //빈칸 여부 확인을 위한 메소드 handlePublish
  const handlePublish = () => {
    if(!입력값.trim()) {
      alert('입력란이 비어 있습니다!');
    } else { //글 발행 기능 추가를 위해서
      let publish_copy = [...글제목];
      let views_change = [...Views];
      let time_change = [...writtenTime];
      let time_Now = new Date();
      publish_copy.unshift(입력값);
      views_change.unshift(0); //따봉갯수 개별적용을 위해 state 변경
      time_change.unshift(time_Now.toLocaleTimeString()); //시간 정보 입력하여 unshift
      plus_views(views_change);
      글제목변경(publish_copy);
      setWrittenTime(time_change);
    }
  };
  
  // document.querySelector('h4').innerHTML = post;

  //참고: JavaScript에서의 Destructuring 문법
  //let [a, c] = [1, 2];
  //자료 잠깐 저장할 땐 변수, state 써도 됨!
  //useState()의 반환값이 위처럼 [?, ?] 이런 식으로 반환되는데, 그런 문법이 적용된 것임
  //일반 변수와 다르게 state쓰던 html은 자동 재렌더링됨 (그래서 state 쓰는 것임!)

  //JSX 문법1. class 넣을 땐 className
  //JSX 문법2. 데이터바인딩은 {중괄호}
  //JSX 문법3. style 넣을 땐 style={{스타일명:'값'}}

  //return() 안에는 병렬로 태그 2개 이상 기입 금지

  //State 변경하는 법
  //->State는 등호로 변경 금지 / state변경함수(새로운state) (ex. span onClick={() => {plus_DDabong(DDabong+1)})

  //(참고)array/object 다룰 때.. 원본은 보존하는 것이 좋음!
  //[state변경함수 특징] 기존 state==신규 state의 경우, 변경해주지 않음(일종의 자원 절약)
  //[array/object 특징] array/object 담은 변수엔 화살표(주솟값 같은 느낌!)만 저장됨 (변수에 직접 저장하는 것이 아님/array, object는 reference data type이라서 그럼!)

  //(참고2)클릭이벤트는 상위 html로 퍼짐 (이벤트 버블링)

  return (
    <div className="App">
      <div className="black-nav">
        <h4 style={{color: 'gray', fontSize: '16px'}}>{logoText}</h4>
      </div>
      <button onClick={() => {
        let copy = [...글제목]; //reference data type이므로.. 이런 식으로 처리해야 변경사항이 정상 반영된다!
        copy.sort();
        글제목변경(copy);
      }}>가나다순 정렬</button>
      <button onClick={() => {
        let copy2 = [...Views]; //reference data type이므로.. 이런 식으로 처리해야 변경사항이 정상 반영된다!
        copy2.map(function(a, i){
          copy2[i] = 0;
        })
        plus_views(copy2);
      }}>따봉 초기화</button>
      <h2>{post_MainName}</h2>

      {/* <div className="list">
        <h4>{글제목[0]} <span onClick={() => {plus_DDabong(DDabong+1)}}>👍</span> {DDabong} </h4>
        <p>2월 14일 발행</p>
      </div>
      
      <div className="list">
        <h4>{글제목[2]}</h4>
        <p>2월 16일 발행</p>
      </div> */}

      {
        //글제목들을 map() 함수를 이용해서 반복 출력 시도
        //상위 html로 퍼지는 이벤트 버블링을 막고 싶으면.. e.stopPropagation()
        글제목.map(function(subject_name, i){
          return (
            <div className="list" key={i}>
              <h4 onClick={()=>{ 
                modal == null ? setModal(i) : setModal(null);
                }}>{subject_name} <span onClick={(e)=>{e.stopPropagation();}}>👍</span> {Views[i]} </h4>
              <p>2월 15일 발행</p>
              <button className="DDABONG_button" onClick={() => { //따봉 수 개별 변경을 위해서..
                let copy = [...Views];
                copy[i] = copy[i]+1;
                plus_views(copy);
                }}>따봉수 올리기</button>
              <button className="Delete_button" onClick={() => { //글 삭제를 위해서...
                let delete_copy = [...글제목];
                let views_change = [...Views];
                let time_copy = [...writtenTime];
                delete_copy.splice(i, 1); //splice()는 반환값이 있긴 하지만.. 필요 없다면 따로 변수에 저장할 필요도 X
                views_change.splice(i, 1); //삭제할 때, 따봉도 같이 없어져야 함
                time_copy.splice(i, 1); //시간 정보도 없애야 하니깐
                plus_views(views_change);
                글제목변경(delete_copy);
                setWrittenTime(time_copy);
              }}>글 삭제</button>
              <h4>시간 표시해줄겁니다: {writtenTime[i]}</h4>
            </div>
          )
        })
      }
      {
        //파라미터 문법은 다양한 기능을 하는 함수를 만들 때 사용함 (실은 props도 파라미터 문법일 뿐, props로 일반 문자도 전송 가능)
        //부모->자식 state 전송하는 법
        //props 전송은 부모->자식만 가능
        //1. <자식컴포넌트 작명={state이름}>
        //2. props 파라미터 등록 후 props.작명 사용
        modal != null ? <Modal color={'yellow'} selected_subject={글제목[modal]} changeFunction={() => {
          let copy333 = [...글제목];
          copy333[0] = "여자코트 추천";
          글제목변경(copy333);
        }}/> : null //html 중간에 조건문 쓰려면 삼항 연산자 쓰세요!
      }
      
      <input id="input_here" onChange={(e)=>{ 
        //(정보)state 변경함수는 늦게 처리됨(전문용어로 비동기처리/React가 애초에 그런 식으로 동작함. 참고하자)
        입력값변경(e.target.value);
        // console.log(입력값);
       }}/>
       <button onClick={handlePublish}>글 발행하기</button>
       <Modal2></Modal2>
    </div>
    
  );
  //<input>에 뭔가 입력 시에 코드를 실행하고 싶으면.. onChange / onInput 
  //위에 onChange={(e)=>..}에서의 e에는.. 지금 발생하는 이벤트에 관련한 여러 기능이 담겨 있음
}

//동적인 UI 만드는 step
//1. html, CSS로 미리 디자인 완성
//2. UI의 현재 상태를 state로 저장
//3. state에 따라 UI가 어떻게 보일지 작성
//중요한 점: state 만드는 곳은 state 사용하는 컴포넌트들 중 최상위 컴포넌트 (생각 귀찮으면 그냥 App에 만드셈)
function Modal(props) {
  return (
    <div className="modal" style={{background: props.color}}>
      <h4>{props.selected_subject}</h4>
      <p>날짜</p>
      <p>상세내용</p>
      <button onClick = {props.changeFunction}>첫번째 제목 "여자 코트 수정"으로 글수정</button>
    </div>
  )
}

//function 문법 말고 class 문법으로도 컴포넌트 생성 가능! (몰라도 되긴 함)
//옛날 React 프로젝트들 보면.. class로 되어 있는거 간혹 볼 수 있으므로.. 참고로 알아두면 좋을 듯!
//class를 쉽게 이해하면.. 변수, 함수 보관함임 (constructor, super, render는 기본 템플릿이라고 생각하면 될 듯!)
class Modal2 extends React.Component {
  constructor(props){
    super(props)
    //class 컴포넌트에서 state 만들려면..
    this.state = {
      name : 'kim',
      age : 20
    }
  }
  render(){
    return (
      <div>안녕 {this.state.age}
        <button onClick={() => {
          this.setState({age : 21});
        }}>age변경!</button>
      </div>
    )
  }
}

export default App;
